import * as THREE from '/binaural-assets/js/vendor/three.module.js';

// Ultra-premium Cymatics Engine V4
// Implements Class A (Particle Simulation) and Class B (SDF Fluid Raymarching)

const PARTICLE_COUNT = 300000;

// Cymatics formulas (Chladni)
const CHLADNI_GLSL = `
#define PI 3.14159265359
float chladni(vec2 p, float n, float m) {
    return cos(n * PI * p.x) * cos(m * PI * p.y) - cos(m * PI * p.x) * cos(n * PI * p.y);
}
`;

/**
 * CLASS A: Glowing Particle Sand Simulation
 * Simulates fine sand gathering at Chladni nodes (where f(x,y) = 0)
 */
export function createParticleCymatics(data) {
    const geometry = new THREE.BufferGeometry();
    const positions = new Float32Array(PARTICLE_COUNT * 3);
    const uvs = new Float32Array(PARTICLE_COUNT * 2);
    const randoms = new Float32Array(PARTICLE_COUNT);

    for (let i = 0; i < PARTICLE_COUNT; i++) {
        // Distribute particles across a 2D plane
        positions[i * 3 + 0] = (Math.random() - 0.5) * 40;
        positions[i * 3 + 1] = (Math.random() - 0.5) * 40;
        positions[i * 3 + 2] = (Math.random() - 0.5) * 2; // slight depth
        
        uvs[i * 2 + 0] = Math.random();
        uvs[i * 2 + 1] = Math.random();
        
        randoms[i] = Math.random();
    }

    geometry.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    geometry.setAttribute('uv', new THREE.BufferAttribute(uvs, 2));
    geometry.setAttribute('aRandom', new THREE.BufferAttribute(randoms, 1));

    const material = new THREE.ShaderMaterial({
        uniforms: {
            uTime: { value: 0 },
            uN: { value: data.n || 1.0 },
            uM: { value: data.m || 1.0 },
            uColor1: { value: new THREE.Color(data.color1 || '#00ffff') },
            uColor2: { value: new THREE.Color(data.color2 || '#ff00ff') },
            uColor3: { value: new THREE.Color(data.color3 || '#ffff00') },
            uIntensity: { value: data.energy || 1.0 },
            uPatternType: { value: data.type || 0.0 }
        },
        vertexShader: `
            uniform float uTime;
            uniform float uN;
            uniform float uM;
            uniform float uIntensity;
            uniform float uPatternType;
            attribute float aRandom;
            varying vec3 vColor;
            varying float vAlpha;
            
            ${CHLADNI_GLSL}
            
            void main() {
                vec3 pos = position;
                vec2 p = pos.xy * 0.1; 
                
                // Rotation/Swirl
                float t = uTime * 0.2;
                mat2 rot = mat2(cos(t), -sin(t), sin(t), cos(t));
                vec2 rp = rot * p;
                
                // Calculate node distance (0 = node)
                float c = chladni(rp, uN, uM);
                
                if (uPatternType > 5.0) {
                    c = chladni(rp, uN, uM) * 0.5 + chladni(rp * 1.5, uN*0.5, uM*0.5) * 0.5;
                }
                
                float distToNode = abs(c);
                
                // Particles move towards nodes (distToNode = 0) over time
                float pull = smoothstep(1.0, 0.0, distToNode) * uIntensity * 10.0;
                
                pos.z += sin(uTime * 3.0 + aRandom * 10.0) * pull * 0.5;
                
                vec4 mvPosition = modelViewMatrix * vec4(pos, 1.0);
                gl_Position = projectionMatrix * mvPosition;
                gl_PointSize = (1.5 + pull * 2.0) * (100.0 / -mvPosition.z);
                
                vAlpha = smoothstep(0.5, 0.0, distToNode) * (0.5 + 0.5 * sin(uTime * 5.0 + aRandom));
                
                // Mix colors based on quadrant and distance
                float ang = atan(pos.y, pos.x);
                vColor = mix(vec3(0.0, 1.0, 1.0), vec3(1.0, 0.0, 1.0), sin(ang + uTime) * 0.5 + 0.5);
            }
        `,
        fragmentShader: `
            uniform vec3 uColor1;
            uniform vec3 uColor2;
            uniform vec3 uColor3;
            varying vec3 vColor;
            varying float vAlpha;
            
            void main() {
                // Circular particle
                float dist = length(gl_PointCoord - vec2(0.5));
                if (dist > 0.5) discard;
                
                // Soft edge glow
                float glow = smoothstep(0.5, 0.2, dist);
                
                vec3 finalColor = mix(uColor1, uColor2, vColor.x);
                finalColor = mix(finalColor, uColor3, vColor.y);
                
                gl_FragColor = vec4(finalColor * glow * 1.5, vAlpha * glow);
            }
        `,
        transparent: true,
        blending: THREE.AdditiveBlending,
        depthWrite: false
    });

    const mesh = new THREE.Points(geometry, material);
    return mesh;
}

/**
 * CLASS B: Fluid Raymarched SDF Cymatics
 * Creates a continuous, liquid-like glowing waveform.
 */
export function createSDFCymatics(data) {
    const geometry = new THREE.PlaneGeometry(100, 100);
    const material = new THREE.ShaderMaterial({
        uniforms: {
            uTime: { value: 0 },
            uN: { value: data.n || 1.0 },
            uM: { value: data.m || 1.0 },
            uColor1: { value: new THREE.Color(data.color1 || '#00ffff') },
            uColor2: { value: new THREE.Color(data.color2 || '#ff00ff') },
            uColor3: { value: new THREE.Color(data.color3 || '#ffff00') },
            uIntensity: { value: data.energy || 1.0 },
            uPatternType: { value: data.type || 0.0 },
            uResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) }
        },
        vertexShader: `
            varying vec2 vUv;
            void main() {
                vUv = uv;
                gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
            }
        `,
        fragmentShader: `
            uniform float uTime;
            uniform float uN;
            uniform float uM;
            uniform vec3 uColor1;
            uniform vec3 uColor2;
            uniform vec3 uColor3;
            uniform float uIntensity;
            uniform float uPatternType;
            varying vec2 vUv;
            
            ${CHLADNI_GLSL}
            
            void main() {
                vec2 p = (vUv - 0.5) * 4.0;
                
                // Swirl
                float t = uTime * 0.3;
                float r = length(p);
                float a = atan(p.y, p.x);
                p = vec2(cos(a + t * 0.5), sin(a + t * 0.5)) * r;
                
                float c = chladni(p, uN, uM);
                
                if (uPatternType > 10.0) {
                    c = abs(c) - 0.2;
                }
                
                float glow = 0.05 / (abs(c) + 0.01);
                glow *= uIntensity;
                
                // Dynamic colors based on SDF gradient
                vec3 col = mix(uColor1, uColor2, sin(c * 10.0 - uTime * 2.0) * 0.5 + 0.5);
                col = mix(col, uColor3, smoothstep(0.0, 1.0, glow * 0.5));
                
                // Add bioluminescence
                col += uColor1 * glow * 1.5;
                
                // Vignette
                float vig = 1.0 - smoothstep(1.0, 2.0, r);
                
                gl_FragColor = vec4(col * vig, 1.0);
            }
        `,
        transparent: true,
        blending: THREE.AdditiveBlending,
        depthWrite: false
    });

    const mesh = new THREE.Mesh(geometry, material);
    return mesh;
}
